import math

def solve(gender, scr, age):
    # Step 1: Determine coefficients A and B based on gender and serum creatinine
    if gender == 'female':
        a = 0.7
        if scr <= 0.7:
            b = -0.241
        else:
            b = -1.2
    elif gender == 'male':
        a = 0.9
        if scr <= 0.9:
            b = -0.302
        else:
            b = -1.2
    else:
        raise ValueError("Gender must be 'female' or 'male'")

    yield {
        "step_name": "determine_coefficients_a_and_b",
        "step_description": "Based on patient gender and serum creatinine (Scr) level, determine the values for coefficients A and B as per the 2021 CKD-EPI Creatinine equation rules.",
        "step_result": {"a": a, "b": b},
        "unit": "dimensionless"
    }

    # Step 2: Determine gender coefficient
    if gender == 'female':
        gender_coefficient = 1.012
    else:
        gender_coefficient = 1.0

    yield {
        "step_name": "determine_gender_coefficient",
        "step_description": "Determine the gender coefficient for the CKD-EPI equation based on patient gender.",
        "step_result": gender_coefficient,
        "unit": "dimensionless"
    }

    # Step 3: Calculate eGFR using the 2021 CKD-EPI Creatinine equation
    egfr = 142 * ((scr / a) ** b) * (0.9938 ** age) * gender_coefficient
    egfr = round(egfr, 4)

    yield {
        "step_name": "calculate_egfr_ckd_epi_2021",
        "step_description": "Compute the estimated Glomerular Filtration Rate (eGFR) using the 2021 CKD-EPI Creatinine equation: 142 * (Scr/A)^B * 0.9938^age * gender_coefficient.",
        "step_result": egfr,
        "unit": "mL/min/1.73 m^2"
    }

    return egfr

import math

def solve(creatinine, age, sex, race):
    # Step 1: gender_coefficient_determination
    # Determine the gender coefficient based on the patient's sex.
    if sex == 'female':
        gender_coefficient = 0.742
    elif sex == 'male':
        gender_coefficient = 1.0
    else:
        raise ValueError("sex must be 'male' or 'female'")

    yield {
        "step_name": "gender_coefficient_determination",
        "step_description": "Determine the gender coefficient based on the patient's sex.",
        "step_result": gender_coefficient,
        "unit": "score"
    }

    # Step 2: race_coefficient_determination
    # Determine the race coefficient for the MDRD equation.
    if race == 'African American':
        race_coefficient = 1.212
    else:
        race_coefficient = 1.0

    yield {
        "step_name": "race_coefficient_determination",
        "step_description": "Determine the race coefficient for the MDRD equation. Defaults to 1.0 if race is not specified or is non-Black.",
        "step_result": race_coefficient,
        "unit": "score"
    }

    # Step 3: mdrd_gfr_calculation
    # Calculate the estimated GFR using the MDRD equation.
    gfr = 175 * math.pow(creatinine, -1.154) * math.pow(age, -0.203) * race_coefficient * gender_coefficient

    yield {
        "step_name": "mdrd_gfr_calculation",
        "step_description": "Calculate the estimated GFR using the MDRD equation.",
        "step_result": gfr,
        "unit": "ml/min/1.73m²"
    }

    return gfr

def solve(gender, height_inches):
    # Step 1: Calculate Ideal Body Weight (IBW) based on gender and height in inches using the Devine formula
    if gender == 'male':
        ibw_kg = 50 + 2.3 * (height_inches - 60)
    elif gender == 'female':
        ibw_kg = 45.5 + 2.3 * (height_inches - 60)
    else:
        raise ValueError("gender must be 'male' or 'female'")

    yield {
        "step_name": "calculate_ibw",
        "step_description": "Calculate Ideal Body Weight (IBW) based on gender and height in inches using the Devine formula.",
        "step_result": ibw_kg,
        "unit": "kg"
    }

    return ibw_kg

def solve(active_cancer, bedridden_or_surgery, calf_swelling, collateral_veins, entire_leg_swollen, localized_tenderness, pitting_edema, paralysis_or_immobilization, previous_dvt, alternative_diagnosis):
    # Step 1: compute_wells_dvt_score
    # Sum the points for each of the 10 clinical criteria based on their presence (True) or absence (False).
    # Each criterion: True -> assigned points, False -> 0 points.
    # Points mapping:
    #   active_cancer +1
    #   bedridden_or_surgery +1
    #   calf_swelling +1
    #   collateral_veins +1
    #   entire_leg_swollen +1
    #   localized_tenderness +1
    #   pitting_edema +1
    #   paralysis_or_immobilization +1
    #   previous_dvt +1
    #   alternative_diagnosis -2
    total_score = 0
    if active_cancer:
        total_score += 1
    if bedridden_or_surgery:
        total_score += 1
    if calf_swelling:
        total_score += 1
    if collateral_veins:
        total_score += 1
    if entire_leg_swollen:
        total_score += 1
    if localized_tenderness:
        total_score += 1
    if pitting_edema:
        total_score += 1
    if paralysis_or_immobilization:
        total_score += 1
    if previous_dvt:
        total_score += 1
    if alternative_diagnosis:
        total_score -= 2

    yield {
        "step_name": "compute_wells_dvt_score",
        "step_description": "Sum the points for each of the 10 clinical criteria based on their presence (True) or absence (False). Points: active_cancer (+1 if True), bedridden_or_surgery (+1), calf_swelling (+1), collateral_veins (+1), entire_leg_swollen (+1), localized_tenderness (+1), pitting_edema (+1), paralysis_or_immobilization (+1), previous_dvt (+1), alternative_diagnosis (-2 if True).",
        "step_result": total_score,
        "unit": "score"
    }

    return total_score

def solve(weight_kg):
    # step 1: calculate_maintenance_fluid
    # Calculate maintenance fluid rate (mL/hr) based on patient weight using conditional evaluation for three weight ranges.
    if weight_kg <= 10:
        maintenance_fluid_rate = 4 * weight_kg
    elif weight_kg <= 20:
        maintenance_fluid_rate = 40 + 2 * (weight_kg - 10)
    else:
        maintenance_fluid_rate = 60 + 1 * (weight_kg - 20)

    # Round result to 4 decimal places if needed
    maintenance_fluid_rate = round(maintenance_fluid_rate, 4)

    yield {
        "step_name": "calculate_maintenance_fluid",
        "step_description": "Calculate maintenance fluid rate (mL/hr) based on patient weight using conditional evaluation for three weight ranges.",
        "step_result": maintenance_fluid_rate,
        "unit": "mL/hr"
    }

    return maintenance_fluid_rate

def solve(systolic_bp, age, renal_disease, liver_disease, stroke_history, prior_bleeding, labile_inr, medication_usage, alcohol_use):
    # Step 1: Hypertension Evaluation
    # Evaluate the hypertension criterion: assign 1 point if systolic blood pressure > 160 mmHg, otherwise 0.
    if systolic_bp > 160:
        hypertension_points = 1
    else:
        hypertension_points = 0
    yield {
        "step_name": "hypertension_evaluation",
        "step_description": "Evaluate the hypertension criterion: assign 1 point if systolic blood pressure > 160 mmHg, otherwise 0.",
        "step_result": hypertension_points,
        "unit": "score"
    }

    # Step 2: Age Evaluation
    # Evaluate the age criterion: assign 1 point if age > 65 years, otherwise 0.
    if age > 65:
        age_points = 1
    else:
        age_points = 0
    yield {
        "step_name": "age_evaluation",
        "step_description": "Evaluate the age criterion: assign 1 point if age > 65 years, otherwise 0.",
        "step_result": age_points,
        "unit": "score"
    }

    # Step 3: Binary Criteria Evaluation
    # Evaluate the remaining 7 binary (Yes/No) clinical criteria and sum their points.
    binary_points = 0
    if renal_disease:
        binary_points += 1
    if liver_disease:
        binary_points += 1
    if stroke_history:
        binary_points += 1
    if prior_bleeding:
        binary_points += 1
    if labile_inr:
        binary_points += 1
    if medication_usage:
        binary_points += 1
    if alcohol_use:
        binary_points += 1
    yield {
        "step_name": "binary_criteria_evaluation",
        "step_description": "Evaluate the remaining 7 binary (Yes/No) clinical criteria and sum their points.",
        "step_result": binary_points,
        "unit": "score"
    }

    # Step 4: Total HAS-BLED Score
    # Sum the points from the hypertension, age, and binary clinical criteria to calculate the total HAS-BLED score.
    total_has_bled_score = hypertension_points + age_points + binary_points
    yield {
        "step_name": "total_has_bled_score",
        "step_description": "Sum the points from the hypertension, age, and binary clinical criteria to calculate the total HAS-BLED score.",
        "step_result": total_has_bled_score,
        "unit": "score"
    }

    return total_has_bled_score

def solve(temperature_celsius, heart_rate_bpm, respiratory_rate_bpm, paco2_mm_hg, wbc_per_mm3, bands_percentage):
    # Step 1: temperature_criteria_evaluation
    # Evaluate whether the patient's temperature meets the SIRS criteria: >38C or <36C.
    if temperature_celsius > 38 or temperature_celsius < 36:
        temp_score = 1
    else:
        temp_score = 0
    yield {
        "step_name": "temperature_criteria_evaluation",
        "step_description": "Evaluate whether the patient's temperature meets the SIRS criteria: >38C or <36C.",
        "step_result": temp_score,
        "unit": "score"
    }

    # Step 2: heart_rate_criteria_evaluation
    # Evaluate whether the patient's heart rate meets the SIRS criteria: >90 bpm.
    if heart_rate_bpm > 90:
        hr_score = 1
    else:
        hr_score = 0
    yield {
        "step_name": "heart_rate_criteria_evaluation",
        "step_description": "Evaluate whether the patient's heart rate meets the SIRS criteria: >90 bpm.",
        "step_result": hr_score,
        "unit": "score"
    }

    # Step 3: respiratory_criteria_evaluation
    # Evaluate whether the patient's respiratory criteria meet the SIRS criteria: respiratory rate >20 bpm OR PaCO2 <32 mm Hg.
    if respiratory_rate_bpm > 20 or paco2_mm_hg < 32:
        resp_score = 1
    else:
        resp_score = 0
    yield {
        "step_name": "respiratory_criteria_evaluation",
        "step_description": "Evaluate whether the patient's respiratory criteria meet the SIRS criteria: respiratory rate >20 bpm OR PaCO2 <32 mm Hg.",
        "step_result": resp_score,
        "unit": "score"
    }

    # Step 4: wbc_criteria_evaluation
    # Evaluate whether the patient's WBC count or bands percentage meets the SIRS criteria: WBC >12,000/mm3, <4,000/mm3, or >10% bands.
    if wbc_per_mm3 > 12000 or wbc_per_mm3 < 4000 or bands_percentage > 10:
        wbc_score = 1
    else:
        wbc_score = 0
    yield {
        "step_name": "wbc_criteria_evaluation",
        "step_description": "Evaluate whether the patient's WBC count or bands percentage meets the SIRS criteria: WBC >12,000/mm3, <4,000/mm3, or >10% bands.",
        "step_result": wbc_score,
        "unit": "score"
    }

    # Step 5: sirs_total_score
    # Calculate the total SIRS score by summing the individual criterion scores.
    total_sirs_score = temp_score + hr_score + resp_score + wbc_score
    yield {
        "step_name": "sirs_total_score",
        "step_description": "Calculate the total SIRS score by summing the individual criterion scores.",
        "step_result": total_sirs_score,
        "unit": "score"
    }

    return total_sirs_score
